import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hi 👋 I'm your AI mental health assistant. I'm here to listen. How are you feeling today?",
    },
  ]);
  const [input, setInput] = useState("");

  const chatEndRef = useRef(null);

  // Auto-scroll to latest message
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Therapist-style emotion replies
  const getBotReply = (text) => {
    const msg = text.toLowerCase();

    if (
      msg.includes("sad") ||
      msg.includes("unhappy") ||
      msg.includes("depressed")
    ) {
      return "I hear you 💜 Feeling sad can be really heavy. Do you want to talk about what's been weighing on you?";
    }

    if (
      msg.includes("tired") ||
      msg.includes("exhausted") ||
      msg.includes("drained")
    ) {
      return "That sounds exhausting 💜 You've been carrying a lot. Have you been getting enough rest lately?";
    }

    if (
      msg.includes("anxious") ||
      msg.includes("stressed") ||
      msg.includes("worried")
    ) {
      return "I'm really glad you shared this 💜 Anxiety can feel overwhelming. Let's take this one step at a time together.";
    }

    if (
      msg.includes("happy") ||
      msg.includes("good") ||
      msg.includes("fine")
    ) {
      return "That's nice to hear 💜 What's been helping you feel this way?";
    }

    return "I'm here with you 💜 Take your time. Would you like to tell me a little more about what's on your mind?";
  };

  const handleSend = () => {
    if (input.trim() === "") return;

    const userMessage = {
      sender: "user",
      text: input,
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput("");

    // Simulate AI thinking
    setTimeout(() => {
      const botMessage = {
        sender: "bot",
        text: getBotReply(userMessage.text),
      };

      setMessages((prev) => [...prev, botMessage]);
    }, 600);
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      handleSend();
    }
  };

  return (
    <div className="chat-page">
      <div className="chat-header">
        🧠 <span>General Chat</span>
      </div>

      <div className="chat-body">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`chat-message ${msg.sender}`}
          >
            <div className="bubble">{msg.text}</div>
          </div>
        ))}
        <div ref={chatEndRef}></div>
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
